import React from 'react';
import { useSiteMetaData } from 'hooks/useSiteMetaData';

interface Props {
  title: string;
  description: string;
  pathname: string;
  image: string;
}
interface SEOItemType {
  title: string;
  description: string;
  url: string;
  image: string;
}

const GTM_SCRIPT = `(function(w,d,s,l,i){w[l]=w[l]||[];w[l].push({'gtm.start':
new Date().getTime(),event:'gtm.js'});var f=d.getElementsByTagName(s)[0],
j=d.createElement(s),dl=l!='dataLayer'?'&l='+l:'';j.async=true;j.src=
'https://www.googletagmanager.com/gtm.js?id='+i+dl;f.parentNode.insertBefore(j,f);
})(window,document,'script','dataLayer', \`${process.env.GATSBY_GTM_CONTAINER_ID}\`);`;

const SEO = ({ title, description, pathname, image }: Props) => {
  const data = useSiteMetaData();
  const { siteMetadata } = data.site;

  const SEOItem: SEOItemType = {
    title: title || siteMetadata.title,
    description: description || siteMetadata.description,
    url: `${siteMetadata.siteUrl}${pathname ?? ''}`,
    image: `${siteMetadata.siteUrl}${image}`,
  };

  return (
    <>
      <title>{siteMetadata.title}</title>
      <link rel="canonical" href={SEOItem.url} />
      <script>{GTM_SCRIPT}</script>

      <meta
        name="google-site-verification"
        content={process.env.GATSBY_GOOGLE_SEARCH_CONSOLE}
      />
      <meta name="author" content="corinthionia Joohyun Kim 김주현" />
      <meta name="description" content={siteMetadata.description} />
      <meta name="viewport" content="width=device-width, initial-scale=1.0" />
      <meta httpEquiv="Content-Type" content="text/html;charset=UTF-8" />

      <meta property="og:type" content="website" />
      <meta property="og:title" content={SEOItem.title} />
      <meta property="og:description" content={SEOItem.description} />
      <meta property="og:url" content={SEOItem.url} />
      <meta property="og:image" content={SEOItem.image} />

      <html lang="ko" />
    </>
  );
};

export default SEO;
